import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.supadata.ai/";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Supadata API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:supadata",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const supadataFirewall = {",
    '  name: "supadata",',
    '  description: "Supadata API",',
    "  placeholders: {",
    `    SUPADATA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.supadata.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-api-key": "${{ secrets.SUPADATA_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Supadata firewall config...");
  const ts = generateTypeScript();
  writeOutput("supadata", ts, import.meta.dirname);
}
